package com.treeeducation.ioas.media.resource; import com.treeeducation.ioas.common.*;import com.treeeducation.ioas.media.assetfile.*;import com.treeeducation.ioas.media.contentpackage.*;import io.swagger.v3.oas.annotations.*;import io.swagger.v3.oas.annotations.media.Schema;import io.swagger.v3.oas.annotations.tags.Tag;import org.springframework.data.domain.*;import org.springframework.web.bind.annotation.*;import java.util.*; /** Shared media resource center APIs. */ @RestController @RequestMapping("/api/v1/media/resources") @Tag(name="Media Resource Center",description="共享文件池目录树、主题包筛选、按类型查询") public class MediaResourceController{private final ContentPackageRepository packages;private final AssetFileService files; public MediaResourceController(ContentPackageRepository packages,AssetFileService files){this.packages=packages;this.files=files;} @Schema(description="资源目录节点") public record TreeNode(String key,String title,String type,Long packageId){} @GetMapping("/tree") @Operation(summary="资源中心目录树") public ApiResponse<List<TreeNode>> tree(){List<TreeNode> roots=new ArrayList<>(); roots.add(new TreeNode("script","脚本","type",null));roots.add(new TreeNode("video","视频","type",null));roots.add(new TreeNode("image","图片","type",null)); packages.findAll().forEach(p->roots.add(new TreeNode("package-"+p.getId(),p.getName(),"package",p.getId()))); return ApiResponse.ok(roots);} @GetMapping("/files") @Operation(summary="资源中心素材筛选") public ApiResponse<PageResponse<AssetFileDtos.Response>> files(@RequestParam(required=false)Long packageId,@RequestParam(required=false)AssetFileType type,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.ok(PageResponse.of(files.list(packageId,type,PageRequest.of(page,size))));}}
